head.script:
//
(function() {
  var t = localStorage.getItem('theme');
  if (t === 'light' || t === null) {
    document.documentElement.classList.add('light-theme');
  }
})();
//

head.b:skin:
/**
* Theme Name: Devil Survivor 2 (Restoration Final)
* Final Checkpoint: Pixel Art Social + Header Alignment + All Fixes
*/

:root { --brand-color: #0860ca; --hover-color: #0860ca; --title-color: #357ebd; }

/* --- ESTILOS BASE --- */
body { margin: 0; padding: 0; background: #000 url(http://1.bp.blogspot.com/-d7NByOREYKU/VpTJ7zJgvUI/AAAAAAAACTw/X6HasrYaVs4/s000/bg_body.gif) repeat fixed top center; font-family: 'Segoe UI', Tahoma, sans-serif; color: #fff; transition: background 0.3s; overflow-x: hidden; }

.light-theme body, body.light-theme { background: #fdfdfd !important; color: #111 !important; }
.light-theme #casing { background: #fff !important; border-color: #eee !important; }
.light-theme .post-tag { background: #f0f0f0 !important; color: #666 !important; }
.light-theme .post-card h2 a { color: #111 !important; }
.light-theme .section-title { border-color: #eee !important; }

#wrapper { width: 100%; margin: 0; position: relative; }

/* HEADER ALIGNMENT */
#header { border-bottom: 1px solid var(--brand-color); position: relative; width: 100%; height: 350px; background-color: #000; background-repeat: no-repeat; background-position: center; background-size: cover; overflow: hidden; }
.header-inner { max-width: 1120px; margin: auto; position: relative; height: 100%; }

h1#blog-title { 
  position: absolute; 
  top: 35px; /* Antes estaba en 25px */
  left: 20px; 
  font-size: 38pt; 
  color: #fff !important; 
  text-shadow: 4px 4px 0px rgba(0,0,0,0.8); 
  text-transform: uppercase; 
  margin: 0; 
  z-index: 10;
  line-height: 45px; /* Esto lo alinea al centro vertical del icono de 45px */
}
h1#blog-title a { color: #fff !important; text-decoration: none !important; border: 0 !important; }

/* --- ICONOS SOCIALES PIXEL ART --- */
.jorib { 
  position: absolute; 
  top: 15px; /* Misma altura que el título */
  right: 20px; 
  z-index: 99; 
  display: flex; 
  list-style: none; 
  padding: 0; 
  margin: 0; 
  gap: 10px; 
}
.jorib li a { 
  display: flex; width: 45px; height: 45px; 
  background-color: var(--brand-color); color: #fff !important; 
  align-items: center; justify-content: center; 
  text-decoration: none !important; border: 3px solid #fff !important; 
  box-shadow: 4px 4px 0px #000; /* Sombra sólida pixel */
  font-size: 22px; transition: 0.1s; position: relative;
}
.jorib li a:hover { 
  transform: translate(2px, 2px); 
  box-shadow: 2px 2px 0px #000;
  background-color: #fff; color: var(--brand-color) !important;
  border-color: var(--brand-color) !important;
}

/* MENÚ ANTI-FLICKER */
.menujohanes { position: relative; width: 1120px; margin: auto; z-index: 1000; height: 40px; }
ul.dark_menu { 
  margin: 0; padding: 0; padding-left: 30px; list-style: none !important; display: flex; margin-top: -45px; float: left; gap: 4px; 
  opacity: 0; transition: opacity 0.3s ease;
}
ul.dark_menu.menu-ready { opacity: 1; }
ul.dark_menu li { position: relative; min-width: 140px; transition: 0.3s; }
ul.dark_menu li:before, ul.dark_menu li ul li:before { content: ""; position: absolute; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.85); transform: skewX(-20deg); transition: 0.3s; z-index: 1; }
ul.dark_menu li:hover:before { background: var(--hover-color) !important; }
ul.dark_menu li a { color: #fff !important; display: block; padding: 12px 18px; text-align: center; position: relative; z-index: 5; text-transform: uppercase; font-size: 12px; font-weight: bold; text-decoration: none !important; border: 0 !important; }

/* SUBMENÚ BRIDGE */
ul.dark_menu li ul { display: none; position: absolute; left: -45px; top: 48px; width: auto; list-style: none !important; z-index: 9999; flex-direction: column; gap: 6px; }
ul.dark_menu li ul:after { content: ""; position: absolute; top: -20px; left: 0; width: 100%; height: 25px; background: transparent; z-index: -1; }
ul.dark_menu li:hover > ul { display: flex; }

/* LUPA SIN LÍNEA */
.nav-tools { float: right; margin-top: -45px; display: flex; margin-right: 20px; gap: 5px; border: 0 !important; outline: 0 !important; }
.tool-btn, .tool-btn *, .tool-btn:before, .tool-btn:after { border: 0 !important; outline: 0 !important; text-decoration: none !important; box-shadow: none !important; }
.tool-btn { position: relative; width: 50px; height: 40px; cursor: pointer; display: flex; align-items: center; justify-content: center; color: #fff !important; z-index: 20; background: none !important; overflow: hidden; }
.tool-btn:before { content: ""; position: absolute; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.8); transform: skewX(-20deg); transition: 0.3s; z-index: 1; }
.tool-btn:hover:before { background: var(--brand-color); }
.tool-btn i { position: relative; z-index: 5; display: block; }

/* CASING Y GRID 3x3 AJAX */
#casing { border: 1px solid var(--brand-color); margin: 10px auto; width: 1120px; background: rgba(113,113,113,0.05); overflow: hidden; padding: 20px 0; min-height: 600px; display: flex; box-sizing: border-box; }
#content-wrapper { width: 800px; padding: 0 20px; box-sizing: border-box; display: flex; flex-direction: column; }
.section-title { font-size: 18px; text-transform: uppercase; margin: 10px 0 20px 0; color: var(--title-color); font-weight: bold; border-bottom: 2px solid rgba(255,255,255,0.1); padding-bottom: 10px; width: 100%; }

#featured-ajax-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 25px; margin-bottom: 40px; width: 100%; }
.latest-grid-container { display: grid !important; grid-template-columns: repeat(3, 1fr) !important; gap: 25px !important; width: 100% !important; min-height: 500px; }

.post-card { display: flex; flex-direction: column; margin-bottom: 20px; }
.post-thumb-wrap { width: 100%; height: 160px; overflow: hidden; border-radius: 4px; margin-bottom: 10px; background: #222; border-bottom: 3px solid transparent; transition: 0.3s;}
#featured-ajax-grid .post-thumb-wrap { height: 210px; }
.post-thumb { width: 100%; height: 100%; object-fit: cover; }
.post-card h2 { margin: 5px 0 3px 0; font-size: 14px; line-height: 1.3; font-weight: bold; height: 38px; overflow: hidden; }
.post-card h2 a { color: inherit; text-decoration: none !important; border: 0 !important; }
.post-card:hover .post-thumb-wrap { border-color: var(--brand-color); }

/* CATEGORÍAS */
.post-labels { display: flex; flex-wrap: wrap; gap: 4px; margin-top: 5px; }
.post-tag { font-size: 9px; text-transform: uppercase; background: rgba(255,255,255,0.1); padding: 2px 5px; border-radius: 2px; color: #999; font-weight: bold; }

/* SIDEBAR SEARCH */
.sidebar { width: 340px; padding-right: 20px; box-sizing: border-box; }
.sidebar-search { margin-bottom: 20px; width: 100%; }
.sidebar-search form { display: flex; border: 1px solid #ccc; background: transparent; padding: 5px 10px; align-items: center; }
.sidebar-search input { border: 0; background: transparent; color: inherit; width: 100%; padding: 8px 0; outline: none; font-size: 14px; }
.sidebar-search button { background: none; border: none; color: #999; cursor: pointer; }

/* PAGINACIÓN */
#blog-pager { clear: both; width: 100%; text-align: center; margin: 30px auto; padding: 20px 0; border-top: 1px solid rgba(255,255,255,0.1); }
.showpageNum a, .showpagePoint { display: inline-block; margin: 0 5px; padding: 6px 14px; color: #ff4c4c !important; font-weight: bold; font-size: 16px; text-decoration: none !important; }
.showpagePoint { color: #fff !important; background: var(--brand-color); border-radius: 2px; }

.fleft { text-align: center; padding: 15px; border: 1px solid var(--brand-color); background: rgba(0,0,0,0.8); color: #999; width: 1120px; margin: 10px auto; }

/* FIX MODO DISEÑO */
body#layout #header, body#layout .menujohanes, body#layout #casing, body#layout .jorib, body#layout .nav-tools, body#layout #content-wrapper, body#layout .sidebar, body#layout .fleft, body#layout .blognames, body#layout .Social, body#layout .Navigation, body#layout .LupaConfig { 
  position: static !important; width: 95% !important; height: auto !important; margin: 15px auto !important; padding: 15px !important; 
  display: block !important; float: none !important; background: #fff !important; border: 1px dashed #666 !important; color: #000 !important; 
  opacity: 1 !important; box-sizing: border-box !important;
}
body#layout ul.dark_menu { opacity: 1 !important; margin: 10px 0 !important; padding: 0 !important; display: block !important; }
body#layout ul.dark_menu li { display: block !important; margin: 5px 0 !important; border: 1px solid #eee !important; }
body#layout ul.dark_menu li:before { display: none !important; }

head.script:
//
var posts_per_page = 9;
var featured_label = "Destacado";

/* MOTOR IMÁGENES HQ */
function getSmartThumb(entry) {
  var thumb = "";
  if (entry.media$thumbnail) { thumb = entry.media$thumbnail.url; } 
  else {
    var content = entry.content ? entry.content.$t : (entry.summary ? entry.summary.$t : "");
    var match = content.match(/<img[^>]+src="([^">]+)"/);
    thumb = match ? match[1] : "https://via.placeholder.com/400x250?text=No+Image";
  }
  if (thumb.indexOf("googleusercontent.com") != -1 || thumb.indexOf("bp.blogspot.com") != -1) {
    thumb = thumb.replace(/\/s[0-9]+.*?\//, "/s1600/").replace(/=s[0-9]+.*/, "=s1600");
  }
  return thumb;
}

/* ETIQUETAS */
function getLabels(entry) {
  var html = '<div class="post-labels">';
  if (entry.category) {
    for (var i = 0; i < entry.category.length; i++) {
      if (entry.category[i].term !== featured_label) {
        html += '<span class="post-tag">' + entry.category[i].term + '</span>';
      }
    }
  }
  html += '</div>';
  return html;
}

function loadFeatured(json) {
  var html = "";
  if(!json.feed.entry) return;
  for (var i = 0; i < json.feed.entry.length; i++) {
    var entry = json.feed.entry[i];
    var title = entry.title.$t;
    var url = entry.link.find(l => l.rel == 'alternate').href;
    var thumb = getSmartThumb(entry);
    var labels = getLabels(entry);
    html += '<div class="post-card"><div class="post-thumb-wrap"><a href="'+url+'"><img class="post-thumb" src="'+thumb+'" style="height:210px"/></a></div><h2><a href="'+url+'">'+title+'</a></h2>'+labels+'</div>';
  }
  document.getElementById("featured-ajax-grid").innerHTML = html;
}

function loadMainGrid(json) {
  var entries = json.feed.entry || [];
  var url = window.location.href;
  var currentPage = url.indexOf("PageNo=") != -1 ? parseInt(url.split("PageNo=")[1]) : 1;
  var filteredEntries = entries.filter(e => !(e.category || []).some(l => l.term === featured_label));
  var start = (currentPage - 1) * posts_per_page;
  var end = start + posts_per_page;
  var pageEntries = filteredEntries.slice(start, end);
  var html = "";
  for (var i = 0; i < pageEntries.length; i++) {
    var entry = pageEntries[i];
    var title = entry.title.$t;
    var postUrl = entry.link.find(l => l.rel == 'alternate').href;
    var thumb = getSmartThumb(entry);
    var labels = getLabels(entry);
    html += '<div class="post-card"><div class="post-thumb-wrap"><a href="'+postUrl+'"><img class="post-thumb" src="'+thumb+'"/></a></div><h2><a href="'+postUrl+'">'+title+'</a></h2>'+labels+'</div>';
  }
  document.getElementById("main-ajax-grid").innerHTML = html;
  var totalPages = Math.ceil(filteredEntries.length / posts_per_page);
  var phtml = "";
  var base_url = url.split("?")[0] + "?max-results=" + posts_per_page;
  if (currentPage > 1) phtml += "<a class='showpageNum' href='"+base_url+"&PageNo="+(currentPage-1)+"'>&lt;</a>";
  for (var j = 1; j <= totalPages; j++) {
    if (j == currentPage) phtml += "<span class='showpagePoint'>"+j+"</span>";
    else phtml += "<a class='showpageNum' href='"+base_url+"&PageNo="+j+"'>"+j+"</a>";
  }
  if (currentPage < totalPages) phtml += "<a class='showpageNum' href='"+base_url+"&PageNo="+(currentPage+1)+"'>&gt;</a>";
  document.getElementById("blog-pager").innerHTML = phtml;
}

$(document).ready(function() {
  /* SUBMENÚS (_) */
  $('.dark_menu li').each(function() {
    var $link = $(this).find('a').first();
    var text = $link.text().trim();
    if (text.indexOf('_') === 0) {
      var $parent = $(this).prevAll().filter(function() { return $(this).find('a').first().text().trim().indexOf('_') !== 0; }).first();
      if ($parent.length) {
        if (!$parent.find('ul').length) { $parent.append('<ul></ul>').addClass('has-children'); }
        $link.text(text.replace('_', ''));
        $(this).detach().appendTo($parent.find('ul'));
      }
    }
  });
  $('.dark_menu').addClass('menu-ready');

  /* TOGGLE TEMA */
  const themeBtn = $('#theme-toggle');
  const htmlEl = $('html');
  themeBtn.on('click', function() {
    if (htmlEl.hasClass('light-theme')) {
      htmlEl.removeClass('light-theme');
      localStorage.setItem('theme', 'dark');
      themeBtn.find('i').attr('class', 'fa-solid fa-sun');
    } else {
      htmlEl.addClass('light-theme');
      localStorage.setItem('theme', 'light');
      themeBtn.find('i').attr('class', 'fa-solid fa-moon');
    }
  });
  if (htmlEl.hasClass('light-theme')) { themeBtn.find('i').attr('class', 'fa-solid fa-moon'); } else { themeBtn.find('i').attr('class', 'fa-solid fa-sun'); }
});
//

b:includable.script:
    (function() {
      var items = ;
      var msgs = ;
      var config = ;

// 
      var cursor = null;
      if (items && items.length > 0) {
        cursor = parseInt(items[items.length - 1].timestamp) + 1;
      }

      var bodyFromEntry = function(entry) {
        var text = (entry &&
                    ((entry.content && entry.content.$t) ||
                     (entry.summary && entry.summary.$t))) ||
            '';
        if (entry && entry.gd$extendedProperty) {
          for (var k in entry.gd$extendedProperty) {
            if (entry.gd$extendedProperty[k].name == 'blogger.contentRemoved') {
              return '<span class="deleted-comment">' + text + '</span>';
            }
          }
        }
        return text;
      }

      var parse = function(data) {
        cursor = null;
        var comments = [];
        if (data && data.feed && data.feed.entry) {
          for (var i = 0, entry; entry = data.feed.entry[i]; i++) {
            var comment = {};
            // comment ID, parsed out of the original id format
            var id = /blog-(\d+).post-(\d+)/.exec(entry.id.$t);
            comment.id = id ? id[2] : null;
            comment.body = bodyFromEntry(entry);
            comment.timestamp = Date.parse(entry.published.$t) + '';
            if (entry.author && entry.author.constructor === Array) {
              var auth = entry.author[0];
              if (auth) {
                comment.author = {
                  name: (auth.name ? auth.name.$t : undefined),
                  profileUrl: (auth.uri ? auth.uri.$t : undefined),
                  avatarUrl: (auth.gd$image ? auth.gd$image.src : undefined)
                };
              }
            }
            if (entry.link) {
              if (entry.link[2]) {
                comment.link = comment.permalink = entry.link[2].href;
              }
              if (entry.link[3]) {
                var pid = /.*comments\/default\/(\d+)\?.*/.exec(entry.link[3].href);
                if (pid && pid[1]) {
                  comment.parentId = pid[1];
                }
              }
            }
            comment.deleteclass = 'item-control blog-admin';
            if (entry.gd$extendedProperty) {
              for (var k in entry.gd$extendedProperty) {
                if (entry.gd$extendedProperty[k].name == 'blogger.itemClass') {
                  comment.deleteclass += ' ' + entry.gd$extendedProperty[k].value;
                } else if (entry.gd$extendedProperty[k].name == 'blogger.displayTime') {
                  comment.displayTime = entry.gd$extendedProperty[k].value;
                }
              }
            }
            comments.push(comment);
          }
        }
        return comments;
      };

      var paginator = function(callback) {
        if (hasMore()) {
          var url = config.feed + '?alt=json&v=2&orderby=published&reverse=false&max-results=50';
          if (cursor) {
            url += '&published-min=' + new Date(cursor).toISOString();
          }
          window.bloggercomments = function(data) {
            var parsed = parse(data);
            cursor = parsed.length < 50 ? null
                : parseInt(parsed[parsed.length - 1].timestamp) + 1
            callback(parsed);
            window.bloggercomments = null;
          }
          url += '&callback=bloggercomments';
          var script = document.createElement('script');
          script.type = 'text/javascript';
          script.src = url;
          document.getElementsByTagName('head')[0].appendChild(script);
        }
      };
      var hasMore = function() {
        return !!cursor;
      };
      var getMeta = function(key, comment) {
        if ('iswriter' == key) {
          var matches = !!comment.author
              && comment.author.name == config.authorName
              && comment.author.profileUrl == config.authorUrl;
          return matches ? 'true' : '';
        } else if ('deletelink' == key) {
          return config.baseUri + '/comment/delete/'
               + config.blogId + '/' + comment.id;
        } else if ('deleteclass' == key) {
          return comment.deleteclass;
        }
        return '';
      };

      var replybox = null;
      var replyUrlParts = null;
      var replyParent = undefined;

      var onReply = function(commentId, domId) {
        if (replybox == null) {
          // lazily cache replybox, and adjust to suit this style:
          replybox = document.getElementById('comment-editor');
          if (replybox != null) {
            replybox.height = '250px';
            replybox.style.display = 'block';
            replyUrlParts = replybox.src.split('#');
          }
        }
        if (replybox && (commentId !== replyParent)) {
          replybox.src = '';
          document.getElementById(domId).insertBefore(replybox, null);
          replybox.src = replyUrlParts[0]
              + (commentId ? '&parentID=' + commentId : '')
              + '#' + replyUrlParts[1];
          replyParent = commentId;
        }
      };

      var hash = (window.location.hash || '#').substring(1);
      var startThread, targetComment;
      if (/^comment-form_/.test(hash)) {
        startThread = hash.substring('comment-form_'.length);
      } else if (/^c[0-9]+$/.test(hash)) {
        targetComment = hash.substring(1);
      }

      // Configure commenting API:
      var configJso = {
        'maxDepth': config.maxThreadDepth
      };
      var provider = {
        'id': config.postId,
        'data': items,
        'loadNext': paginator,
        'hasMore': hasMore,
        'getMeta': getMeta,
        'onReply': onReply,
        'rendered': true,
        'initComment': targetComment,
        'initReplyThread': startThread,
        'config': configJso,
        'messages': msgs
      };

      var render = function() {
        if (window.goog && window.goog.comments) {
          var holder = document.getElementById('comment-holder');
          window.goog.comments.render(holder, provider);
        }
      };

      // render now, or queue to render when library loads:
      if (window.goog && window.goog.comments) {
        render();
      } else {
        window.goog = window.goog || {};
        window.goog.comments = window.goog.comments || {};
        window.goog.comments.loadQueue = window.goog.comments.loadQueue || [];
        window.goog.comments.loadQueue.push(render);
      }
    })();
//
